INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'AG', 'ag', 'Agricultural District', 'The purpose of the AG (agricultural district) is to provide an area for agricultural pursuits protected from infringement of urban development. It also provides for very low density single-family uses and associated accessory uses.', 35, NULL, 15000, NULL, 20, 6, 5, 'Off-street parking and loading requirements are generally outlined in Section 24-78 of the Laredo Land Development Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'ag' AND z.city_id = (SELECT id FROM cities WHERE slug = 'laredo') AND pu.name IN ('Agriculture not involving livestock', 'Horticulture', 'Riding academy', 'Single-family dwelling') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'R-1', 'r-1', 'Single Family Residential District', 'The principal purpose of the R-1 (single-family residential) zoning district is to conserve and protect single-family residential development. It provides areas for low-density residential neighborhoods consisting of single-family dwelling units.', 35, NULL, 6000, NULL, 20, 6, 5, 'Off-street parking and loading requirements are generally outlined in Section 24-78 of the Laredo Land Development Code. Dimensional standards for parking spaces for single-family dwellings are 8 feet wide and 16 feet long.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'laredo') AND pu.name IN ('Single-family dwelling', 'Churches', 'Day care centers', 'Golf courses', 'Parks, public and private', 'Public and quasi-public uses', 'Public utility facilities', 'Schools, public and private') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'R-1A', 'r-1a', 'Single Family Reduced Area District', 'This district provides for single-family residential development on reduced area lots. It aims to accommodate a higher density of single-family homes compared to the R-1 district.', 35, NULL, 4500, NULL, 20, 6, 5, 'Off-street parking and loading requirements are generally outlined in Section 24-78 of the Laredo Land Development Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
