INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'R-1B', 'r-1b', 'Single Family High Density District', 'The purpose of R-1B zoning districts is to provide for residential uses and those public uses normally considered an integral part of the residential neighborhood they serve. This district allows for the subdivision of single-family residential lots with a minimum of 3,000 square feet.', 35, NULL, 3000, NULL, 20, 6, 5, 'Off-street parking and loading requirements are generally outlined in Section 24-78 of the Laredo Land Development Code.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
