INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'R-2', 'r-2', 'Multi-Family Residential District', 'The R-2 district is intended to permit medium and high-density residential uses, including multi-family, two-family, and single-family structures. It also allows for related recreational, religious, and educational facilities.', 50, NULL, 1200, NULL, 20, 20, 5, 'Off-street parking and loading requirements are generally outlined in Section 24-78 of the Laredo Land Development Code. Zoning laws specify where duplexes can be built, mainly in areas like R-2 meant for multifamily housing.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
